import{_ as e}from"./chunks/alink_window.BEamZtgc.js";import{c as n,Q as i,j as t,m as s}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Installing Adaptive-Link for OpenIPC","description":"Detailed guide for setting up Adaptive-Link","frontmatter":{"title":"Installing Adaptive-Link for OpenIPC","description":"Detailed guide for setting up Adaptive-Link","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/configuration/adaptive-link"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/configuration/adaptive-link"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/configuration/adaptive-link"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/configuration/adaptive-link"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/configuration/adaptive-link"}],["meta",{"property":"og:title","content":"Installing Adaptive-Link for OpenIPC"}],["meta",{"property":"og:description","content":"Detailed guide for setting up Adaptive-Link"}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-config.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-config.png"}],["meta",{"name":"twitter:title","content":"Installing Adaptive-Link for OpenIPC"}],["meta",{"name":"twitter:description","content":"Detailed guide for setting up Adaptive-Link"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Configuration\\",\\"item\\":\\"https://openfpv.com.ua/en/configuration/multiconfigurator\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Installing Adaptive-Link for OpenIPC\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Installing Adaptive-Link for OpenIPC\\",\\"description\\":\\"Detailed guide for setting up Adaptive-Link\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/configuration/adaptive-link\\",\\"image\\":\\"https://openfpv.com.ua/og-config.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/configuration/adaptive-link.md","filePath":"en/configuration/adaptive-link.md","lastUpdated":1780228136000}'),l={name:"en/configuration/adaptive-link.md"};function o(r,a,p,c,d,h){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h2 id="what-is-adaptive-link" tabindex="-1">What is Adaptive-Link? <a class="header-anchor" href="#what-is-adaptive-link" aria-label="Permalink to &quot;What is Adaptive-Link?&quot;">​</a></h2><p><strong>Adaptive-Link</strong> is a system that <strong>automatically adjusts video and link quality</strong> between the drone and the ground station based on signal strength.</p><blockquote><p>When you are close — video is clear and smooth. When far away — quality decreases, but the link remains stable.</p></blockquote><div class="info custom-block"><p class="custom-block-title">Info</p><p>In other words, you no longer need to manually set transmit power!</p></div><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p><strong>Adaptive-Link</strong> automatically controls:</p><ul><li>Bitrate</li><li>Transmitter power</li><li>MCS, SNR, RSSI parameters</li><li>FEC and QoS depending on distance and conditions</li></ul><hr><h2 id="installing-adaptive-link-on-radxa-gs" tabindex="-1">Installing Adaptive-Link on Radxa GS <a class="header-anchor" href="#installing-adaptive-link-on-radxa-gs" aria-label="Permalink to &quot;Installing Adaptive-Link on Radxa GS&quot;">​</a></h2><ol><li>Image v1.9.9 or newer → disable Wi-Fi card power.</li><li>Reboot Radxa and log in as <code>radxa/radxa</code> or <code>root/root</code>.</li><li>Run <code>nmtui</code> — connect to your home Wi-Fi.</li><li>SSH → run:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo curl -L -o alink_install.sh https://raw.githubusercontent.com/OpenIPC/adaptive-link/refs/heads/main/alink_install.sh</span></span>
<span class="line"><span>sudo chmod +x alink_install.sh</span></span>
<span class="line"><span>sudo ./alink_install.sh gs remove</span></span>
<span class="line"><span>sudo ./alink_install.sh gs install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Wait for the update to finish. Reboot the VRX.</p><hr><h2 id="installing-adaptive-link-on-runcam-wifilink-v1-v2-cameras" tabindex="-1">Installing Adaptive-Link on Runcam WiFiLink V1/V2 Cameras <a class="header-anchor" href="#installing-adaptive-link-on-runcam-wifilink-v1-v2-cameras" aria-label="Permalink to &quot;Installing Adaptive-Link on Runcam WiFiLink V1/V2 Cameras&quot;">​</a></h2><ol><li>Download <strong><a href="https://github.com/OpenIPC/openipc-configurator" target="_blank" rel="noreferrer">Multiconfigurator</a></strong>.</li><li>Extract and launch it.</li><li>Connect to the camera at <code>192.168.1.10</code> (password <code>12345</code>).</li><li>Click <strong>Connect</strong> (turns blue when camera is reachable); after connecting the camera type, sensor and Wi-Fi card are detected.</li><li>Go to <strong>Firmware → Runcam → Wifilink → fpv</strong> and click <strong>Update</strong>.</li><li>After the update:<br> Open Telemetry → enable UART0, add Mavlink.<br> Enable Alink Drone → Enable.</li></ol><p>After the camera connects to the Radxa you should see this window:<br><img src="`+e+`" alt="" width="400px"><br></p><div class="warning custom-block"><p class="custom-block-title">Warning!</p><p>If it doesn&#39;t appear — <code>adaptive_link</code> is <strong>NOT</strong> working.</p></div><p>Edit the configuration file on the Air Unit — only a few values matter:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/etc/alink.conf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Here you set whether RSSI or SNR takes priority:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>snr</span></span>
<span class="line"><span>rssi_weight=0,5</span></span>
<span class="line"><span>snr_weight=0,5</span></span>
<span class="line"><span>osd_level=5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><code>osd_level</code> controls how many lines of info Adaptive-Link displays (bitrate, CPU load, etc.) — range 0–5.</p><hr><h2 id="force-enabling-adaptive-link" tabindex="-1">Force-Enabling Adaptive Link <a class="header-anchor" href="#force-enabling-adaptive-link" aria-label="Permalink to &quot;Force-Enabling Adaptive Link&quot;">​</a></h2><ol><li>Open WinSCP.</li><li>Connect to the camera via FTP/SSH.</li><li>Open <code>/etc/rc.local</code> and insert before <code>exit</code>:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>alink_drone &amp;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol start="4"><li>To overclock the CPU (optional): open <code>/etc/rc.local</code> and add:</li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> performance</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/scaling_governor</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1200000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/policy0/scaling_min_freq</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1200000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/devices/system/cpu/cpu0/cpufreq/policy0/scaling_max_freq</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="warning custom-block"><p class="custom-block-title">Note!</p><p><strong>Warning:</strong> some cameras may behave unstably with overclocking — test on the bench first!</p></div><hr><h2 id="safe-tx-profiles" tabindex="-1">Safe TX Profiles <a class="header-anchor" href="#safe-tx-profiles" aria-label="Permalink to &quot;Safe TX Profiles&quot;">​</a></h2><p>txprofile files for network cards — <a href="https://github.com/OpenIPC/adaptive-link/tree/main/txprofiles" target="_blank" rel="noreferrer">here</a> (<em>filename must always be</em> <code>txprofile.conf</code>)</p><p>Example safe TX profile:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># &lt;range&gt; &lt;gi&gt; &lt;mcs&gt; &lt;fecK&gt; &lt;fecN&gt; &lt;bitrate&gt; &lt;gop&gt; &lt;Pwr&gt; &lt;roiQP&gt; &lt;bandwidth&gt; &lt;qpDelta&gt;</span></span>
<span class="line"><span>999 - 999   long 0 8 12 1999 10 30 0,0,0,0 20 -12</span></span>
<span class="line"><span>1000 - 1050 long 0 8 12 2000 10 30 0,0,0,0 20 -12</span></span>
<span class="line"><span>1051 - 1500 long 1 8 12 4000 10 25 0,0,0,0 20 -12</span></span>
<span class="line"><span>1501 - 1950 long 2 8 12 8000 10 20 12,6,6,12 20 -12</span></span>
<span class="line"><span>1951 - 2001 short 2 8 12 9000 10 20 12,6,6,12 20 -12</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="tx-file-parameters" tabindex="-1">TX File Parameters <a class="header-anchor" href="#tx-file-parameters" aria-label="Permalink to &quot;TX File Parameters&quot;">​</a></h2><ul><li><strong>range</strong> — range for adaptive transmission.</li><li><strong>gi</strong> — guard interval.</li><li><strong>mcs</strong> — modulation and coding scheme.</li><li><strong>fecK</strong> — number of data symbols in FEC.</li><li><strong>fecN</strong> — total number of symbols in FEC.</li><li><strong>bitrate</strong> — data transmission rate (bits/s).</li><li><strong>gop</strong> — keyframe interval.</li><li><strong>Pwr</strong> — transmitter power level.</li><li><strong>roiQP</strong> — quantisation for region of interest.</li><li><strong>bandwidth</strong> — channel bandwidth.</li><li><strong>qpDelta</strong> — corrective QP difference.</li></ul><hr>`,39)])])}const k=n(l,[["render",o]]);export{m as __pageData,k as default};
